"use client";

import React, { useState, useMemo } from "react";
import Link from "next/link";
import {
  Search,
  Globe,
  CheckCircle2,
  Cpu,
  ArrowRight,
  Sparkles,
} from "lucide-react";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Select } from "@/components/ui/select";
import { PageHeader } from "@/components/page-header";
import ScoreRing from "@/components/ScoreRing";
import { MOCK_DIRECTORY_ENTRIES } from "@/lib/mock-data";

function getScoreColor(score: number): string {
  if (score >= 80) return "text-emerald-400";
  if (score >= 60) return "text-amber-400";
  if (score >= 40) return "text-orange-400";
  return "text-red-400";
}

function getScoreBadgeVariant(
  score: number
): "success" | "warning" | "destructive" {
  if (score >= 70) return "success";
  if (score >= 50) return "warning";
  return "destructive";
}

const INDUSTRIES = [
  { value: "", label: "Toutes les industries" },
  { value: "SaaS", label: "SaaS" },
  { value: "Energie", label: "Energie" },
  { value: "Juridique", label: "Juridique" },
  { value: "Sante", label: "Sante" },
  { value: "Education", label: "Education" },
  { value: "Finance", label: "Finance" },
  { value: "Restauration", label: "Restauration" },
];

export default function DirectoryPage() {
  const [search, setSearch] = useState("");
  const [industry, setIndustry] = useState("");

  const filteredEntries = useMemo(() => {
    return MOCK_DIRECTORY_ENTRIES.filter((entry) => {
      const matchesSearch =
        !search ||
        entry.name.toLowerCase().includes(search.toLowerCase()) ||
        entry.domain.toLowerCase().includes(search.toLowerCase());
      const matchesIndustry = !industry || entry.industry === industry;
      return matchesSearch && matchesIndustry;
    });
  }, [search, industry]);

  return (
    <div className="p-4 sm:p-8 max-w-7xl mx-auto">
      <PageHeader
        title="Annuaire AEO"
        description="Decouvrez les entreprises optimisees pour les moteurs IA"
        actions={
          <Button size="lg">
            <Sparkles className="h-4 w-4" />
            Rejoindre l&apos;annuaire
          </Button>
        }
      />

      {/* Filters */}
      <Card className="p-4 mb-8">
        <div className="flex flex-col sm:flex-row gap-4">
          <div className="flex-1">
            <Input
              placeholder="Rechercher par nom ou domaine..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              icon={<Search className="h-4 w-4" />}
            />
          </div>
          <div className="w-full sm:w-64">
            <Select
              options={INDUSTRIES}
              value={industry}
              onChange={(e) => setIndustry(e.target.value)}
              placeholder="Filtrer par industrie"
            />
          </div>
        </div>
      </Card>

      {/* Results count */}
      <div className="mb-4 text-sm text-white/40">
        {filteredEntries.length} entreprise{filteredEntries.length !== 1 ? "s" : ""} trouvee{filteredEntries.length !== 1 ? "s" : ""}
      </div>

      {/* Directory Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
        {filteredEntries.map((entry) => (
          <Link key={entry.id} href={`/app/directory/${entry.id}`}>
            <Card className="h-full p-5 hover:border-primary/30 cursor-pointer group transition-all duration-300">
              <div className="flex items-start justify-between mb-4">
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 mb-1">
                    <h3 className="text-base font-semibold text-white truncate">
                      {entry.name}
                    </h3>
                    {entry.verified && (
                      <CheckCircle2 className="h-4 w-4 text-primary shrink-0" />
                    )}
                  </div>
                  <div className="flex items-center gap-1.5 text-white/40 text-sm">
                    <Globe className="h-3.5 w-3.5" />
                    <span className="truncate">{entry.domain}</span>
                  </div>
                </div>
                <div className="shrink-0 ml-3">
                  <ScoreRing score={entry.score} size={56} strokeWidth={5} noAnimation />
                </div>
              </div>

              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <Badge variant={getScoreBadgeVariant(entry.score)}>
                    {entry.industry}
                  </Badge>
                </div>
                <div className="flex items-center gap-1.5 text-xs text-white/40">
                  <Cpu className="h-3.5 w-3.5" />
                  <span>{entry.engines} moteur{entry.engines !== 1 ? "s" : ""}</span>
                </div>
              </div>

              <div className="mt-3 pt-3 border-t border-white/5 flex items-center justify-between">
                <span className={`text-sm font-bold ${getScoreColor(entry.score)}`}>
                  Score {entry.score}/100
                </span>
                <ArrowRight className="h-4 w-4 text-white/20 group-hover:text-primary group-hover:translate-x-1 transition-all" />
              </div>
            </Card>
          </Link>
        ))}
      </div>

      {filteredEntries.length === 0 && (
        <Card className="p-12 text-center">
          <div className="text-white/20 mb-4">
            <Search className="h-12 w-12 mx-auto" />
          </div>
          <h3 className="text-lg font-semibold text-white mb-2">
            Aucun resultat
          </h3>
          <p className="text-white/40 text-sm">
            Essayez de modifier vos criteres de recherche ou de filtrage.
          </p>
        </Card>
      )}
    </div>
  );
}

