                                ? "bg-red-500"
                                : level <= 2
                                ? "bg-orange-500"
                                : level <= 3
                                ? "bg-amber-500"
                                : "bg-emerald-500"
                              : "bg-white/10"
                          }`}
                        />
                      ))}
                    </div>
                  </div>
                )}

                <div className="flex justify-end pt-2">
                  <Button
                    onClick={handlePasswordChange}
                    isLoading={passwordLoading}
                    disabled={!currentPassword || !newPassword || !confirmPassword}
                  >
                    <Lock className="h-4 w-4" />
                    Modifier le mot de passe
                  </Button>
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Danger Zone */}
          <Card className="border-red-500/20">
            <CardHeader>
              <CardTitle className="flex items-center gap-2 text-red-400">
                <AlertTriangle className="h-5 w-5" />
                Zone de danger
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-4">
                <div className="p-4 rounded-xl bg-red-500/5 border border-red-500/10">
                  <h4 className="text-sm font-medium text-red-400 mb-1">
                    Supprimer mon compte
                  </h4>
                  <p className="text-xs text-white/40 mb-4">
                    Cette action est irreversible. Toutes vos donnees, projets
                    et credits seront definitivement supprimes.
                  </p>
                  <Button
                    variant="destructive"
                    size="sm"
                    onClick={handleDeleteAccount}
                    isLoading={deleteLoading}
                  >
                    <Trash2 className="h-4 w-4" />
                    {deleteConfirm
                      ? "Confirmer la suppression"
                      : "Supprimer mon compte"}
                  </Button>
                  {deleteConfirm && !deleteLoading && (
                    <Button
                      variant="ghost"
                      size="sm"
                      className="ml-2"
                      onClick={() => setDeleteConfirm(false)}
                    >
                      Annuler
                    </Button>
                  )}
                </div>
              </div>
            </CardContent>
          </Card>
        </div>

        {/* Sidebar */}
        <div className="space-y-6">
          {/* Notification Preferences */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Bell className="h-5 w-5 text-primary" />
                Notifications
              </CardTitle>
            </CardHeader>
            <CardContent>
              <div className="space-y-4">
                {/* Email Alerts Toggle */}
                <div className="flex items-center justify-between">
                  <div className="flex-1 pr-4">
                    <p className="text-sm font-medium text-white">
                      Alertes email
                    </p>
                    <p className="text-xs text-white/40">
                      Nouvelles citations et mentions
                    </p>
                  </div>
                  <button
                    onClick={() =>
                      handleNotificationToggle("emailAlerts", !emailAlerts)
                    }
                    className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
                      emailAlerts ? "bg-primary" : "bg-white/10"
                    }`}
                  >
                    <span
                      className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                        emailAlerts ? "translate-x-6" : "translate-x-1"
                      }`}
                    />
                  </button>
                </div>

                {/* Weekly Digest Toggle */}
                <div className="flex items-center justify-between">
                  <div className="flex-1 pr-4">
                    <p className="text-sm font-medium text-white">
                      Digest hebdomadaire
                    </p>
                    <p className="text-xs text-white/40">
                      Resume de vos performances
                    </p>
                  </div>
                  <button
                    onClick={() =>
                      handleNotificationToggle("weeklyDigest", !weeklyDigest)
                    }
                    className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
                      weeklyDigest ? "bg-primary" : "bg-white/10"
                    }`}
                  >
                    <span
                      className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                        weeklyDigest ? "translate-x-6" : "translate-x-1"
                      }`}
                    />
                  </button>
                </div>

                {/* Marketing Toggle */}
                <div className="flex items-center justify-between">
                  <div className="flex-1 pr-4">
                    <p className="text-sm font-medium text-white">
                      Communications marketing
                    </p>
                    <p className="text-xs text-white/40">
                      Nouveautes et offres speciales
                    </p>
                  </div>
                  <button
                    onClick={() =>
                      handleNotificationToggle("marketing", !marketing)
                    }
                    className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
                      marketing ? "bg-primary" : "bg-white/10"
                    }`}
                  >
                    <span
                      className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                        marketing ? "translate-x-6" : "translate-x-1"
                      }`}
                    />
                  </button>
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Data Export */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Download className="h-5 w-5 text-primary" />
                Export des donnees
              </CardTitle>
            </CardHeader>
            <CardContent>
              <p className="text-sm text-white/40 mb-4">
                Telechargez une copie de toutes vos donnees au format JSON.
                L&apos;export inclut vos projets, analyses, et contenus generes.
              </p>
              <Button
                variant="outline"
                className="w-full"
                onClick={handleExportData}
                isLoading={exportLoading}
              >
                <Download className="h-4 w-4" />
                Exporter mes donnees
              </Button>
            </CardContent>
          </Card>

          {/* Account Info */}
          <Card className="p-5">
            <h3 className="text-sm font-medium text-white/40 mb-3">
              Informations du compte
            </h3>
            <div className="space-y-2.5">
              <div className="flex items-center justify-between text-sm">
                <span className="text-white/40">ID utilisateur</span>
                <span className="text-white/60 font-mono text-xs">
                  {MOCK_USER.id}
                </span>
              </div>
              <div className="flex items-center justify-between text-sm">
                <span className="text-white/40">Plan</span>
                <Badge variant="default" className="capitalize">
                  {MOCK_USER.plan}
                </Badge>
              </div>
              <div className="flex items-center justify-between text-sm">
                <span className="text-white/40">Role</span>
                <span className="text-white/60 capitalize">
                  {MOCK_USER.role}
                </span>
              </div>
              <div className="flex items-center justify-between text-sm">
                <span className="text-white/40">Workspace</span>
                <span className="text-white/60">{MOCK_USER.workspaceId}</span>
              </div>
            </div>
          </Card>
        </div>
      </div>
    </div>
  );
}

